import React from 'react';
import './TeamCollaboration.css';

interface TeamMemberProps {
  name: string;
  role: string;
  project: string;
  status: 'Completed' | 'In Progress' | 'Pending';
  avatar: string;
}

const TeamMember: React.FC<TeamMemberProps> = ({ name, role, project, status, avatar }) => {
  return (
    <div className="team-member">
      <div className="member-info">
        <div className="member-avatar">
          <img src={avatar} alt={name} />
        </div>
        <div className="member-details">
          <h4>{name}</h4>
          <p className="member-role">{role}</p>
          <p className="member-project">Working on {project}</p>
        </div>
      </div>
      <div className={`status-badge ${status.toLowerCase().replace(' ', '-')}`}>
        {status}
      </div>
    </div>
  );
};

const TeamCollaboration: React.FC = () => {
  return (
    <div className="team-collaboration">
      <div className="team-header">
        <h3>Team Collaboration</h3>
        <button className="add-member-btn">+ Add Member</button>
      </div>

      <div className="team-members">
        <TeamMember
          name="Alexandra Deff"
          role="Frontend Developer"
          project="GitHub Project Repository"
          status="Completed"
          avatar="https://images.unsplash.com/photo-1494790108755-2616b612b786?w=40&h=40&fit=crop&crop=face"
        />
        <TeamMember
          name="Edwin Adenike"
          role="Backend Developer"
          project="Integrate User Authentication System"
          status="In Progress"
          avatar="https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=40&h=40&fit=crop&crop=face"
        />
        <TeamMember
          name="Isaac Oluwatemiloun"
          role="UI/UX Designer"
          project="Develop Search and Filter Functionality"
          status="Pending"
          avatar="https://images.unsplash.com/photo-1500648767791-00dcc994a43e?w=40&h=40&fit=crop&crop=face"
        />
        <TeamMember
          name="David Oshodi"
          role="Full Stack Developer"
          project="Responsive Layout for Homepage"
          status="In Progress"
          avatar="https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?w=40&h=40&fit=crop&crop=face"
        />
      </div>
    </div>
  );
};

export default TeamCollaboration;
